  ('social-worker-moex-04030', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '青少年的從眾性及希望自己受歡迎，常常讓他們為服膺同儕而做了不適當的決定與行為。青 少年社會工作人員在協助青少年應對從眾性的壓力，下列方法何者錯誤？', '["直接告訴青少年做什麼", "協助青少年聽取自己的聲音", "討論如何在個人自主與他人期待中取得一個平衡點", "訓練社會拒絕技巧"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "0cea0105bd5f", "answer_pdf_sha1": "50abfa77128e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04031', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '老年階段常有許多失落、悲傷、哀悼，下列敘述何者錯誤？', '["悲傷工作從難以置信，進展到痛苦紊亂，繼之到遷就妥協", "預期失落會發生時，就不會受到影響", "悲傷會同時有生理與心理反應", "哀悼過程包含處理思念亡者的哀傷情緒及恢復生活嘗試新的角色關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "0cea0105bd5f", "answer_pdf_sha1": "50abfa77128e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04032', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '媽媽注意到小翔（男生）從小和一般嬰幼兒不同，小翔3歲時在幼兒園老師的建議下，爸媽 帶小翔進行發展遲緩早期療育評估，在一系列評估後小翔被診斷為泛自閉症障礙症候群。下 列對小翔的敘述，何者錯誤？', '["固定例行的作息或儀式有助於小翔日常生活", "小翔是男生，罹患的可能性比女生高", "小翔不太有視線接觸", "小翔與其他幼兒園兒童會一起分享和經常互動"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "0cea0105bd5f", "answer_pdf_sha1": "50abfa77128e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04033', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Tavris與Wade（1984）提出家庭主婦症候群（housewifesyndrome），主要概念是下列何者？', '["不具有經濟主導權導致女性貧窮化", "社會不重視家庭主婦價值導致容易自我批評", "以女性為主體的家庭概念", "因為不快樂導致受到暴力對待"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "0cea0105bd5f", "answer_pdf_sha1": "50abfa77128e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
